function buildRotatedItems() {
  const out = [];
  let k = 0;
  for (const row of SEED_ITEMS) {
    out.push({
      question: row.q,
      options: [...row.o],
      answer: row.a,
      explanation: row.e,
      key: `seed:${k}`,
    });
    k += 1;
  }
  for (let i = 0; i < LEX.length; i += 1) {
    const w = LEX[i];
    const fn = Q_TYPES[i % Q_TYPES.length];
    const item = fn(w, i);
    out.push({
      question: item.q,
      options: [...item.o],
      answer: item.a,
      explanation: item.e,
      key: `lex:${w}:${i % Q_TYPES.length}`,
    });
  }
  return out;
}

const built = buildRotatedItems();

if (built.length !== 200) {
  throw new Error(`grade6SinhalaBank (මුල් පිටුව): expected 200 items, got ${built.length}`);
}

const keys = new Set();
for (const row of built) {
  if (keys.has(row.key)) throw new Error(`duplicate key ${row.key}`);
  keys.add(row.key);
  const qk = row.question.trim();
  if (keys.has(`q:${qk}`)) throw new Error('duplicate question text');
  keys.add(`q:${qk}`);
}

